import React from "react";
import useMovieTrailer from "../utils/useMovieTrailer";

const Video = (props) => {
  const { id } = props;
  const trailer = useMovieTrailer(id);
  return (
    <div className="w-full h-[40vh] sm:h-[60vh] md:h-[70vh] lg:h-[100vh]  overflow-hidden flex place-items-center">
      <iframe
        width={2058}
        height={1600}
        src={`https://www.youtube.com/embed/${trailer?.key}?showinfo=0&controls=0&rel=0&iv_load_policy=3&modestbranding=1&autoplay=1&loop=1`}
        title="trailer"
        allowFullScreen
      ></iframe>
    </div>
  );
};

export default Video;
